<template>
	<div>
		<!-- еӣҫзүҮдёҠдј з»„д»¶иҫ…еҠ©-->
		<div style="border: 1px solid #ccc">
			<Toolbar style="border-bottom: 1px solid #ccc" :editor="editorRef" :defaultConfig="toolbarConfig"
				:mode="mode" />
			<Editor style="height: 500px; overflow-y: hidden;" v-model="valueHtml" :defaultConfig="editorConfig"
				:mode="mode" @onCreated="handleCreated" @onChange="handleChange" />
		</div>
	</div>
</template>
<script setup>
	import '@wangeditor/editor/dist/css/style.css' // еј•е…Ҙ css

	import {
		onBeforeUnmount,
		ref,
		shallowRef,
		onMounted,
		getCurrentInstance,
		defineEmits
	} from 'vue'
	const context = getCurrentInstance()?.appContext.config.globalProperties;
	import {
		Editor,
		Toolbar
	} from '@wangeditor/editor-for-vue'
	const emit = defineEmits(['change'])
	// зј–иҫ‘еҷЁе®һдҫӢпјҢеҝ…йЎ»з”Ё shallowRef
	const editorRef = shallowRef()
	
	// еҶ…е®№ HTML
	const valueHtml = ref('')
	
	// жЁЎжӢҹ ajax ејӮжӯҘиҺ·еҸ–еҶ…е®№
	onMounted(() => {
		setTimeout(() => {
			valueHtml.value = ''
		}, 1500)
	})
	const mode = 'default' // жҲ– 'simple'
	const toolbarConfig = {
		excludeKeys: ['fullScreen', 'group-video', 'insertLink', 'insertImage']
	}
	const editorConfig = {
		placeholder: 'иҜ·иҫ“е…ҘеҶ…е®№...',
		fontSize:['12px','14px','16px'],
		MENU_CONF: {
			uploadImage: {
				server: context?.$config.name + '/file/upload',
				fieldName: 'file',
				// еҚ•дёӘж–Үд»¶зҡ„жңҖеӨ§дҪ“з§ҜйҷҗеҲ¶пјҢй»ҳи®Өдёә 2M
				maximgSize: 10 * 1024 * 1024, // 10M
				// жңҖеӨҡеҸҜдёҠдј еҮ дёӘж–Үд»¶пјҢй»ҳи®Өдёә 100
				maxNumberOfimgs: 10,
				// йҖүжӢ©ж–Үд»¶ж—¶зҡ„зұ»еһӢйҷҗеҲ¶пјҢй»ҳи®Өдёә ['image/*'] гҖӮеҰӮдёҚжғійҷҗеҲ¶пјҢеҲҷи®ҫзҪ®дёә []
				allowedimgTypes: ['image/*'],
				// иҮӘе®ҡд№үдёҠдј еҸӮж•°пјҢдҫӢеҰӮдј йҖ’йӘҢиҜҒзҡ„ token зӯүгҖӮеҸӮж•°дјҡиў«ж·»еҠ еҲ° formData дёӯпјҢдёҖиө·дёҠдј еҲ°жңҚеҠЎз«ҜгҖӮ
				meta: {
					// token: 'xxx',
					// otherKey: 'yyy'
					// img:''
				},
				// е°Ҷ meta жӢјжҺҘеҲ° url еҸӮж•°дёӯпјҢй»ҳи®Ө false
				metaWithUrl: false,
	
				// иҮӘе®ҡд№үеўһеҠ  http  header
				headers: {
					'Token':context?.$toolUtil.storageGet('Token')
				},
	
				// и·ЁеҹҹжҳҜеҗҰдј йҖ’ cookie пјҢй»ҳи®Өдёә false
				withCredentials: true,
	
				// и¶…ж—¶ж—¶й—ҙпјҢй»ҳи®Өдёә 10 з§’
				timeout: 10 * 1000, //10 з§’
	
				// дёҠдј еүҚ
				onBeforeUpload(imgs) {
					context?.$toolUtil.message('еӣҫзүҮжӯЈеңЁдёҠдј дёӯ,иҜ·иҖҗеҝғзӯүеҫ…','warning')
					return imgs;
				},
				// иҮӘе®ҡд№үжҸ’е…ҘеӣҫзүҮ
				customInsert(res, insertFn) {
					// еӣ дёәиҮӘе®ҡд№үжҸ’е…ҘеҜјиҮҙonSuccessдёҺonFailedеӣһи°ғеҮҪж•°дёҚиө·дҪңз”Ё,иҮӘе·ұжүӢеҠЁеӨ„зҗҶ
	
					if (res.code === 0) {
						context?.$toolUtil.message('еӣҫзүҮдёҠдј жҲҗеҠҹ','success')
					} else {
						context?.$toolUtil.message('еӣҫзүҮдёҠдј еӨұиҙҘпјҢиҜ·йҮҚж–°е°қиҜ•','error')
					}
					// д»Һ res дёӯжүҫеҲ° url alt href пјҢз„¶еҗҺжҸ’е…ҘеӣҫзүҮ
					insertFn(context?.$config.url + 'file/' + res.file);
					// console.log(res, "res.data")
				},
	
				// еҚ•дёӘж–Үд»¶дёҠдј жҲҗеҠҹд№ӢеҗҺ
				onSuccess(img, res) {
				},
	
				// еҚ•дёӘж–Үд»¶дёҠдј еӨұиҙҘ
				onFailed(img, res) {
				},
	
				// дёҠдј иҝӣеәҰзҡ„еӣһи°ғеҮҪж•°
				onProgress(progress) {
					// console.log('progress', progress);
					// progress жҳҜ 0-100 зҡ„ж•°еӯ—
				},
	
				// дёҠдј й”ҷиҜҜпјҢжҲ–иҖ…и§ҰеҸ‘ timeout и¶…ж—¶
				onError(img, err, res) {
					// console.log(`${img.name} дёҠдј еҮәй”ҷ`, err, res);
				}
			}
		}
	}
	
	// з»„д»¶й”ҖжҜҒж—¶пјҢд№ҹеҸҠж—¶й”ҖжҜҒзј–иҫ‘еҷЁ
	onBeforeUnmount(() => {
		const editor = editorRef.value
		if (editor == null) return
		editor.destroy()
	})
	const handleChange=(e)=>{
		emit('change',editorRef.value.getHtml())
	}
	const handleCreated = (editor) => {
		editorRef.value = editor // и®°еҪ• editor е®һдҫӢпјҢйҮҚиҰҒпјҒ
	}
</script>

<style>
	.editor {
		line-height: normal !important;
	}

	.ql-snow .ql-tooltip[data-mode="link"]::before {
		content: "иҜ·иҫ“е…Ҙй“ҫжҺҘең°еқҖ:";
	}

	.ql-snow .ql-tooltip.ql-editing a.ql-action::after {
		border-right: 0px;
		content: "дҝқеӯҳ";
		padding-right: 0px;
	}

	.ql-snow .ql-tooltip[data-mode="video"]::before {
		content: "иҜ·иҫ“е…Ҙи§Ҷйў‘ең°еқҖ:";
	}

	.ql-container {
		height: 400px;
	}

	.ql-snow .ql-picker.ql-size .ql-picker-label::before,
	.ql-snow .ql-picker.ql-size .ql-picker-item::before {
		content: "14px";
	}

	.ql-snow .ql-picker.ql-size .ql-picker-label[data-value="small"]::before,
	.ql-snow .ql-picker.ql-size .ql-picker-item[data-value="small"]::before {
