					</el-form-item>
				</el-col>

				<el-col :span="8">
					<el-form-item label="еҹ№и®ӯж—¶й—ҙ" prop="peixunshijian">
						<el-input class="list_inp" v-model="form.peixunshijian" placeholder="еҹ№и®ӯж—¶й—ҙ"
							 type="text" 							:readonly="!isAdd||disabledForm.peixunshijian?true:false" />
					</el-form-item>
				</el-col>

				<el-col :span="8">
					<el-form-item label="еҹ№и®ӯең°еқҖ" prop="peixundizhi">
						<el-input class="list_inp" v-model="form.peixundizhi" placeholder="еҹ№и®ӯең°еқҖ"
							 type="text" 							:readonly="!isAdd||disabledForm.peixundizhi?true:false" />
					</el-form-item>
				</el-col>

				<el-col :span="8">
					<el-form-item label="еҹ№и®ӯи®ЎеҲ’" prop="peixunjihua">
						<el-input class="list_inp" v-model="form.peixunjihua" placeholder="еҹ№и®ӯи®ЎеҲ’"
							 type="text" 							:readonly="!isAdd||disabledForm.peixunjihua?true:false" />
					</el-form-item>
				</el-col>

				<el-col :span="8">
					<el-form-item label="еҹ№и®ӯжқҗж–ҷ" prop="peixuncailiao">
						<el-input class="list_inp" v-model="form.peixuncailiao" placeholder="еҹ№и®ӯжқҗж–ҷ"
							 type="text" 							:readonly="!isAdd||disabledForm.peixuncailiao?true:false" />
					</el-form-item>
				</el-col>

				<el-col :span="8">
					<el-form-item label="е‘ҳе·Ҙе·ҘеҸ·" prop="yuangonggonghao">
						<el-input class="list_inp" v-model="form.yuangonggonghao" placeholder="е‘ҳе·Ҙе·ҘеҸ·"
							 type="text" 							:readonly="!isAdd||disabledForm.yuangonggonghao?true:false" />
					</el-form-item>
				</el-col>

				<el-col :span="8">
					<el-form-item label="е‘ҳе·Ҙе§“еҗҚ" prop="yuangongxingming">
						<el-input class="list_inp" v-model="form.yuangongxingming" placeholder="е‘ҳе·Ҙе§“еҗҚ"
							 type="text" 							:readonly="!isAdd||disabledForm.yuangongxingming?true:false" />
					</el-form-item>
				</el-col>

				<el-col :span="8">
					<el-form-item label="дё“е‘ҳиҙҰеҸ·" prop="zhuanyuanzhanghao">
						<el-input class="list_inp" v-model="form.zhuanyuanzhanghao" placeholder="дё“е‘ҳиҙҰеҸ·"
							 type="text" 							:readonly="!isAdd||disabledForm.zhuanyuanzhanghao?true:false" />
					</el-form-item>
				</el-col>

				<el-col :span="24">
					<el-form-item label="еҹ№и®ӯеҶ…е®№" prop="peixunneirong">
						<el-input v-model="form.peixunneirong" placeholder="еҹ№и®ӯеҶ…е®№" type="textarea"
						:readonly="!isAdd||disabledForm.peixunneirong?true:false"
						/>
					</el-form-item>
				</el-col>
			</el-row>
			<div class="formModel_btn_box">
				<el-button class="formModel_cancel" @click="backClick">еҸ–ж¶Ҳ</el-button>
				<el-button class="formModel_confirm" @click="save"
					type="success"
					>
					дҝқеӯҳ
				</el-button>
			</div>
		</el-form>
	</div>
</template>
<script setup>
	import {
		ref,
		getCurrentInstance,
		watch,
		onUnmounted,
		onMounted,
		nextTick,
		computed
	} from 'vue';
	import {
		useRoute,
		useRouter
	} from 'vue-router';
	const context = getCurrentInstance()?.appContext.config.globalProperties;
	const route = useRoute()
	const router = useRouter()
	//еҹәзЎҖдҝЎжҒҜ
	const tableName = 'canjiapeixun'
	const formName = 'еҸӮеҠ еҹ№и®ӯ'
	//еҹәзЎҖдҝЎжҒҜ
	const breadList = ref([{
		name: formName
	}])
	//иҺ·еҸ–е”ҜдёҖж ҮиҜҶ
	const getUUID =()=> {
      return new Date().getTime();
    }
	//formиЎЁеҚ•
	const form = ref({
		peixunzhuti: '',
		peixunshijian: '',
		peixundizhi: '',
		peixunjihua: '',
		peixuncailiao: '',
		peixunneirong: '',
		yuangonggonghao: '',
		yuangongxingming: '',
		zhuanyuanzhanghao: '',
	})
	const formRef = ref(null)
	const id = ref(0)
	const type = ref('')
	const disabledForm = ref({
		peixunzhuti : false,
		peixunshijian : false,
		peixundizhi : false,
		peixunjihua : false,
		peixuncailiao : false,
		peixunneirong : false,
		yuangonggonghao : false,
		yuangongxingming : false,
		zhuanyuanzhanghao : false,
	})
	const isAdd = ref(false)
	//иЎЁеҚ•йӘҢиҜҒ
	//еҢ№й…Қж•ҙж•°
	const validateIntNumber = (rule, value, callback) => {
		if (!value) {
			callback();
		} else if (!context?.$toolUtil.isIntNumer(value)) {
			callback(new Error("иҜ·иҫ“е…Ҙж•ҙж•°"));
		} else {
			callback();
		}
	}
	//еҢ№й…Қж•°еӯ—
	const validateNumber = (rule, value, callback) => {
		if(!value){
			callback();
		} else if (!context?.$toolUtil.isNumber(value)) {
			callback(new Error("иҜ·иҫ“е…Ҙж•°еӯ—"));
		} else {
			callback();
		}
	}
	//еҢ№й…ҚжүӢжңәеҸ·з Ғ
	const validateMobile = (rule, value, callback) => {
		if(!value){
			callback();
		} else if (!context?.$toolUtil.isMobile(value)) {
			callback(new Error("иҜ·иҫ“е…ҘжӯЈзЎ®зҡ„жүӢжңәеҸ·з Ғ"));
		} else {
			callback();
		}
	}
	//еҢ№й…Қз”өиҜқеҸ·з Ғ
	const validatePhone = (rule, value, callback) => {
		if(!value){
			callback();
		} else if (!context?.$toolUtil.isPhone(value)) {
			callback(new Error("иҜ·иҫ“е…ҘжӯЈзЎ®зҡ„з”өиҜқеҸ·з Ғ"));
		} else {
			callback();
		}
	}
	//еҢ№й…ҚйӮ®з®ұ
	const validateEmail = (rule, value, callback) => {
		if(!value){
			callback();
		} else if (!context?.$toolUtil.isEmail(value)) {
			callback(new Error("иҜ·иҫ“е…ҘжӯЈзЎ®зҡ„йӮ®з®ұең°еқҖ"));
		} else {
			callback();
		}
	}
	//еҢ№й…Қиә«д»ҪиҜҒ
	const validateIdCard = (rule, value, callback) => {
		if(!value){
			callback();
		} else if (!context?.$toolUtil.checkIdCard(value)) {
			callback(new Error("иҜ·иҫ“е…ҘжӯЈзЎ®зҡ„иә«д»ҪиҜҒеҸ·з Ғ"));
		} else {
			callback();
		}
	}
	//еҢ№й…ҚзҪ‘з«ҷең°еқҖ
	const validateUrl = (rule, value, callback) => {
		if(!value){
			callback();
		} else if (!context?.$toolUtil.isURL(value)) {
			callback(new Error("иҜ·иҫ“е…ҘжӯЈзЎ®зҡ„URLең°еқҖ"));
		} else {
			callback();
		}
	}
	const rules = ref({
		peixunzhuti: [
			{required: true,message: 'иҜ·иҫ“е…Ҙ',trigger: 'blur'}, 
		],
		peixunshijian: [
			{required: true,message: 'иҜ·иҫ“е…Ҙ',trigger: 'blur'}, 
		],
		peixundizhi: [
			{required: true,message: 'иҜ·иҫ“е…Ҙ',trigger: 'blur'}, 
		],
		peixunjihua: [
		],
		peixuncailiao: [
		],
		peixunneirong: [
		],
		yuangonggonghao: [
		],
		yuangongxingming: [
		],
		zhuanyuanzhanghao: [
		],
	})
	//methods

	//methods
	//иҺ·еҸ–info
	const getInfo = ()=>{
		context?.$http({
			url: `${tableName}/info/${id.value}`,
			method: 'get'
		}).then(res => {
			let reg=new RegExp('../../../file','g')
			form.value = res.data.data
		})
	}
	const crossRow = ref('')
	const crossTable = ref('')
	const crossTips = ref('')
	const crossColumnName = ref('')
	const crossColumnValue = ref('')
	//еҲқе§ӢеҢ–
	const init = (formId=null,formType='add',formNames='',row=null,table=null,statusColumnName=null,tips=null,statusColumnValue=null) => {
		if(formId){
			id.value = formId
			type.value = formType
		}
		if(formType == 'add'){
			isAdd.value = true
		}else if(formType == 'info'){
			isAdd.value = false
			getInfo()
		}else if(formType == 'edit'){
			isAdd.value = true
			getInfo()
		}
		else if(formType == 'cross'){
			isAdd.value = true
			// getInfo()
			for(let x in row){
				if(x=='peixunzhuti'){
					form.value.peixunzhuti = row[x];
					disabledForm.value.peixunzhuti = true;
					continue;
				}
				if(x=='peixunshijian'){
					form.value.peixunshijian = row[x];
					disabledForm.value.peixunshijian = true;
					continue;
				}
				if(x=='peixundizhi'){
					form.value.peixundizhi = row[x];
					disabledForm.value.peixundizhi = true;
					continue;
				}
				if(x=='peixunjihua'){
					form.value.peixunjihua = row[x];
					disabledForm.value.peixunjihua = true;
					continue;
				}
				if(x=='peixuncailiao'){
					form.value.peixuncailiao = row[x];
					disabledForm.value.peixuncailiao = true;
					continue;
				}
				if(x=='peixunneirong'){
					form.value.peixunneirong = row[x];
					disabledForm.value.peixunneirong = true;
					continue;
				}
				if(x=='yuangonggonghao'){
					form.value.yuangonggonghao = row[x];
					disabledForm.value.yuangonggonghao = true;
					continue;
				}
				if(x=='yuangongxingming'){
					form.value.yuangongxingming = row[x];
					disabledForm.value.yuangongxingming = true;
					continue;
				}
				if(x=='zhuanyuanzhanghao'){
					form.value.zhuanyuanzhanghao = row[x];
					disabledForm.value.zhuanyuanzhanghao = true;
					continue;
				}
			}
			if(row){
				crossRow.value = row
			}
			if(table){
				crossTable.value = table
			}
			if(tips){
				crossTips.value = tips
			}
			if(statusColumnName){
				crossColumnName.value = statusColumnName
			}
			if(statusColumnValue){
				crossColumnValue.value = statusColumnValue
			}
		}
		context?.$http({
			url: `${context?.$toolUtil.storageGet('frontSessionTable')}/session`,
			method: 'get'
		}).then(res => {
			var json = res.data.data
			if(json.hasOwnProperty('yuangonggonghao') && context?.$toolUtil.storageGet("frontRole")!="з®ЎзҗҶе‘ҳ"){
				form.value.yuangonggonghao = json.yuangonggonghao
				disabledForm.value.yuangonggonghao = true;
			}
			if(json.hasOwnProperty('yuangongxingming') && context?.$toolUtil.storageGet("frontRole")!="з®ЎзҗҶе‘ҳ"){
				form.value.yuangongxingming = json.yuangongxingming
				disabledForm.value.yuangongxingming = true;
			}
		})
	}
	//еҲқе§ӢеҢ–
	//еҸ–ж¶Ҳ
	const backClick = () => {
		history.back()
	}
	//жҸҗдәӨ
	const save=()=>{
		var table = crossTable.value
		var objcross = JSON.parse(JSON.stringify(crossRow.value))
		let crossUserId = ''
		let crossRefId = ''
		let crossOptNum = ''
		if(type.value == 'cross'){
			if(crossColumnName.value!=''){
				if(!crossColumnName.value.startsWith('[')){
					for(let o in objcross){
						if(o == crossColumnName.value){
							objcross[o] = crossColumnValue.value
						}
					}
					//дҝ®ж”№и·ЁиЎЁж•°жҚ®
					changeCrossData(objcross)
				}else{
					crossUserId = context?.$toolUtil.storageGet('userid')
					crossRefId = objcross['id']
					crossOptNum = crossColumnName.value.replace(/\[/,"").replace(/\]/,"")
				}
			}
		}
		formRef.value.validate((valid)=>{
			if(valid){
				if(crossUserId&&crossRefId){
					form.value.crossuserid = crossUserId
					form.value.crossrefid = crossRefId
					let params = {
						page: 1,
						limit: 1000, 
						crossuserid:form.value.crossuserid,
						crossrefid:form.value.crossrefid,
					}
					context?.$http({
						url: `${tableName}/page`,
						method: 'get', 
						params: params 
					}).then(res=>{
						if(res.data.data.total>=crossOptNum){
							context?.$toolUtil.message(`${crossTips.value}`,'error')
							return false
						}else{
							context?.$http({
								url: `${tableName}/${!form.value.id ? "save" : "update"}`,
								method: 'post', 
								data: form.value 
							}).then(res=>{
								context?.$toolUtil.message(`ж“ҚдҪңжҲҗеҠҹ`,'success',()=>{
									history.back()
								})
							})
						}
					})
				}else{
					context?.$http({
						url: `${tableName}/${!form.value.id ? "save" : "update"}`,
						method: 'post', 
						data: form.value 
					}).then(res=>{
						context?.$toolUtil.message(`ж“ҚдҪңжҲҗеҠҹ`,'success',()=>{
							history.back()
						})
					})
				}
			}
		})
	}
	//дҝ®ж”№и·ЁиЎЁж•°жҚ®
	const changeCrossData=(row)=>{
		context?.$http({
			url: `${crossTable.value}/update`,
			method: 'post',
			data: row
		}).then(res=>{})
	}
	onMounted(()=>{
		type.value = route.query.type?route.query.type:'add'
		let row = null
		let table = null
		let statusColumnName = null
		let tips = null
		let statusColumnValue = null
		if(type.value == 'cross'){
			row = context?.$toolUtil.storageGet('crossObj')?JSON.parse(context?.$toolUtil.storageGet('crossObj')):{}
			table = context?.$toolUtil.storageGet('crossTable')
			statusColumnName = context?.$toolUtil.storageGet('crossStatusColumnName')
			tips = context?.$toolUtil.storageGet('crossTips')
			statusColumnValue = context?.$toolUtil.storageGet('crossStatusColumnValue')
		}
		init(route.query.id?route.query.id:null, type.value,'', row, table, statusColumnName, tips, statusColumnValue)
	})
	
</script>
<style lang="scss" scoped>
	// йқўеҢ…еұ‘зӣ’еӯҗ
	.bread_view {
		border-radius: 0px;
		padding: 12px 0px;
		margin: 0px auto;
		background: none;
		width: 100%;
		border-color: #eee;
		border-width: 0 0 0px;
		position: relative;
		border-style: solid;
		:deep(.breadcrumb) {
			font-size: 14px;
			line-height: 1;
			.el-breadcrumb__separator {
				margin: 0 9px;
				color: #999;
				font-weight: 500;
			}
			.first_breadcrumb {
				.el-breadcrumb__inner {
					color: #333;
					display: inline-block;
				}
			}
			.second_breadcrumb {
				.el-breadcrumb__inner {
					color: #999;
					display: inline-block;
				}
			}
		}
	}
	// иЎЁеҚ•
	.add_form{
		border: 1px solid #ddd;
		border-radius: 0px;
		padding: 40px 7% 50px;
		background: #fff;
		// form item
		:deep(.el-form-item) {
			border: 0px solid #eee;
			padding: 6px 0;
			margin: 0 0 20px 0;
			background: none;
			display: flex;
			//label
			.el-form-item__label {
			 background: none;
			 display: block;
			 width: auto;
			 min-width: 150px;
			 text-align: right;
			}
			// еҶ…е®№зӣ’еӯҗ
			.el-form-item__content {
				display: flex;
				width: calc(100% - 150px);
				justify-content: flex-start;
				align-items: center;
				flex-wrap: wrap;
				// иҫ“е…ҘжЎҶ
				.list_inp {
					padding: 0 10px;
					background: #fff;
					width: auto;
					border-color: #ccc;
					border-width: 1px;
					line-height: 36px;
					box-sizing: border-box;
					border-style: solid;
					min-width: 100%;
					height: 36px;
					//еҺ»жҺүй»ҳи®Өж ·ејҸ
					.el-input__wrapper{
						border: none;
						box-shadow: none;
						background: none;
						border-radius: 0;
						height: 100%;
						padding: 0;
					}
					.is-focus {
						box-shadow: none !important;
					}
				}
				// й•ҝж–Үжң¬
				.el-textarea__inner {
					border: 1px solid #ccc;
					border-radius: 0px;
					padding: 12px;
					color: #666;
					background: #fff;
					width: 100%;
					font-size: 14px;
					min-height: 120px;
				}
			}
		}
	}
	// жҢүй’®зӣ’еӯҗ
	.formModel_btn_box {
		padding: 0 150px;
		display: flex;
		width: 100%;
		justify-content: center;
		align-items: center;
		.formModel_cancel {
			border: 0px solid #ccc;
			cursor: pointer;
			border-radius: 0px;
			padding: 0 40px;
			margin: 0 20px 0 0;
			color: #fff;
			background: rgb(45, 152, 243);
			width: auto;
			font-size: 14px;
			line-height: 40px;
			transition: all 0.3s;
			height: 40px;
		}
		.formModel_cancel:hover {
		}
		
		.formModel_confirm {
			border: 0px solid #11396190;
			cursor: pointer;
			border-radius: 0px;
			padding: 0 40px;
			margin: 0 20px 0 0;
			color: #fff;
			background: #f03d36;
			width: auto;
			font-size: 14px;
			line-height: 40px;
			transition: all 0.3s;
			height: 40px;
		}
		.formModel_confirm:hover {
		}
	}
</style>