	}])
	//иҺ·еҸ–е”ҜдёҖж ҮиҜҶ
	const getUUID =()=> {
      return new Date().getTime();
    }
	//formиЎЁеҚ•
	const form = ref({
		yuangonggonghao: '',
		yuangongxingming: '',
		bumen: '',
		yuangongkaoqin: '',
		gongzuotaidu: '',
		yewunengli: '',
		gongzuojixiao: '',
		pingjiadengji: '',
		beizhu: '',
		kaoheshijian: '',
		zhuanyuanzhanghao: '',
	})
	const formRef = ref(null)
	const id = ref(0)
	const type = ref('')
	const disabledForm = ref({
		yuangonggonghao : false,
		yuangongxingming : false,
		bumen : false,
		yuangongkaoqin : false,
		gongzuotaidu : false,
		yewunengli : false,
		gongzuojixiao : false,
		pingjiadengji : false,
		beizhu : false,
		kaoheshijian : false,
		zhuanyuanzhanghao : false,
	})
	const isAdd = ref(false)
	//иЎЁеҚ•йӘҢиҜҒ
	//еҢ№й…Қж•ҙж•°
	const validateIntNumber = (rule, value, callback) => {
		if (!value) {
			callback();
		} else if (!context?.$toolUtil.isIntNumer(value)) {
			callback(new Error("иҜ·иҫ“е…Ҙж•ҙж•°"));
		} else {
			callback();
		}
	}
	//еҢ№й…Қж•°еӯ—
	const validateNumber = (rule, value, callback) => {
		if(!value){
			callback();
		} else if (!context?.$toolUtil.isNumber(value)) {
			callback(new Error("иҜ·иҫ“е…Ҙж•°еӯ—"));
		} else {
			callback();
		}
	}
	//еҢ№й…ҚжүӢжңәеҸ·з Ғ
	const validateMobile = (rule, value, callback) => {
		if(!value){
			callback();
		} else if (!context?.$toolUtil.isMobile(value)) {
			callback(new Error("иҜ·иҫ“е…ҘжӯЈзЎ®зҡ„жүӢжңәеҸ·з Ғ"));
		} else {
			callback();
		}
	}
	//еҢ№й…Қз”өиҜқеҸ·з Ғ
	const validatePhone = (rule, value, callback) => {
		if(!value){
			callback();
		} else if (!context?.$toolUtil.isPhone(value)) {
			callback(new Error("иҜ·иҫ“е…ҘжӯЈзЎ®зҡ„з”өиҜқеҸ·з Ғ"));
		} else {
			callback();
		}
	}
	//еҢ№й…ҚйӮ®з®ұ
	const validateEmail = (rule, value, callback) => {
		if(!value){
			callback();
		} else if (!context?.$toolUtil.isEmail(value)) {
			callback(new Error("иҜ·иҫ“е…ҘжӯЈзЎ®зҡ„йӮ®з®ұең°еқҖ"));
		} else {
			callback();
		}
	}
	//еҢ№й…Қиә«д»ҪиҜҒ
	const validateIdCard = (rule, value, callback) => {
		if(!value){
			callback();
		} else if (!context?.$toolUtil.checkIdCard(value)) {
			callback(new Error("иҜ·иҫ“е…ҘжӯЈзЎ®зҡ„иә«д»ҪиҜҒеҸ·з Ғ"));
		} else {
			callback();
		}
	}
	//еҢ№й…ҚзҪ‘з«ҷең°еқҖ
	const validateUrl = (rule, value, callback) => {
		if(!value){
			callback();
		} else if (!context?.$toolUtil.isURL(value)) {
			callback(new Error("иҜ·иҫ“е…ҘжӯЈзЎ®зҡ„URLең°еқҖ"));
		} else {
			callback();
		}
	}
	const rules = ref({
		yuangonggonghao: [
		],
		yuangongxingming: [
		],
		bumen: [
		],
		yuangongkaoqin: [
		],
		gongzuotaidu: [
		],
		yewunengli: [
		],
		gongzuojixiao: [
		],
		pingjiadengji: [
		],
		beizhu: [
		],
		kaoheshijian: [
		],
		zhuanyuanzhanghao: [
		],
	})
	//е‘ҳе·Ҙе·ҘеҸ·еҲ—иЎЁ
	const yuangonggonghaoLists = ref([])
	//е‘ҳе·ҘиҖғеӢӨеҲ—иЎЁ
	const yuangongkaoqinLists = ref([])
	//е·ҘдҪңжҖҒеәҰеҲ—иЎЁ
	const gongzuotaiduLists = ref([])
	//дёҡеҠЎиғҪеҠӣеҲ—иЎЁ
	const yewunengliLists = ref([])
	//е·ҘдҪңз»©ж•ҲеҲ—иЎЁ
	const gongzuojixiaoLists = ref([])
	//иҜ„д»·зӯүзә§еҲ—иЎЁ
	const pingjiadengjiLists = ref([])
	//methods

	//methods
	//иҺ·еҸ–info
	const getInfo = ()=>{
		context?.$http({
			url: `${tableName}/info/${id.value}`,
			method: 'get'
		}).then(res => {
			let reg=new RegExp('../../../file','g')
			form.value = res.data.data
		})
	}
	const crossRow = ref('')
	const crossTable = ref('')
	const crossTips = ref('')
	const crossColumnName = ref('')
	const crossColumnValue = ref('')
	//еҲқе§ӢеҢ–
	const init = (formId=null,formType='add',formNames='',row=null,table=null,statusColumnName=null,tips=null,statusColumnValue=null) => {
			form.value.kaoheshijian = context?.$toolUtil.getCurDateTime()
		if(formId){
			id.value = formId
			type.value = formType
		}
		if(formType == 'add'){
			isAdd.value = true
		}else if(formType == 'info'){
			isAdd.value = false
			getInfo()
		}else if(formType == 'edit'){
			isAdd.value = true
			getInfo()
		}
		else if(formType == 'cross'){
			isAdd.value = true
			// getInfo()
			for(let x in row){
				if(x=='yuangonggonghao'){
					form.value.yuangonggonghao = row[x];
					disabledForm.value.yuangonggonghao = true;
					continue;
				}
				if(x=='yuangongxingming'){
					form.value.yuangongxingming = row[x];
					disabledForm.value.yuangongxingming = true;
					continue;
				}
				if(x=='bumen'){
					form.value.bumen = row[x];
					disabledForm.value.bumen = true;
					continue;
				}
				if(x=='yuangongkaoqin'){
					form.value.yuangongkaoqin = row[x];
					disabledForm.value.yuangongkaoqin = true;
					continue;
				}
				if(x=='gongzuotaidu'){
					form.value.gongzuotaidu = row[x];
					disabledForm.value.gongzuotaidu = true;
					continue;
				}
				if(x=='yewunengli'){
					form.value.yewunengli = row[x];
					disabledForm.value.yewunengli = true;
					continue;
				}
				if(x=='gongzuojixiao'){
					form.value.gongzuojixiao = row[x];
					disabledForm.value.gongzuojixiao = true;
					continue;
				}
				if(x=='pingjiadengji'){
					form.value.pingjiadengji = row[x];
					disabledForm.value.pingjiadengji = true;
					continue;
				}
				if(x=='beizhu'){
					form.value.beizhu = row[x];
					disabledForm.value.beizhu = true;
					continue;
				}
				if(x=='kaoheshijian'){
					form.value.kaoheshijian = row[x];
					disabledForm.value.kaoheshijian = true;
					continue;
				}
				if(x=='zhuanyuanzhanghao'){
					form.value.zhuanyuanzhanghao = row[x];
					disabledForm.value.zhuanyuanzhanghao = true;
					continue;
				}
			}
			if(row){
				crossRow.value = row
			}
			if(table){
				crossTable.value = table
			}
			if(tips){
				crossTips.value = tips
			}
			if(statusColumnName){
				crossColumnName.value = statusColumnName
			}
			if(statusColumnValue){
				crossColumnValue.value = statusColumnValue
			}
		}
		context?.$http({
			url: `${context?.$toolUtil.storageGet('frontSessionTable')}/session`,
			method: 'get'
		}).then(res => {
			var json = res.data.data
			if(json.hasOwnProperty('zhuanyuanzhanghao') && context?.$toolUtil.storageGet("frontRole")!="з®ЎзҗҶе‘ҳ"){
				form.value.zhuanyuanzhanghao = json.zhuanyuanzhanghao
				disabledForm.value.zhuanyuanzhanghao = true;
			}
		})
		context?.$http({
			url: `option/yuangong/yuangonggonghao`,
			method: 'get'
		}).then(res=>{
			yuangonggonghaoLists.value = res.data.data
		})
		//з”ұдёҠзә§еӯ—ж®өеёҰеҮәдёҚеҸҜж”№
		disabledForm.value.yuangongxingming = true;
		//з”ұдёҠзә§еӯ—ж®өеёҰеҮәдёҚеҸҜж”№
		disabledForm.value.bumen = true;
		yuangongkaoqinLists.value = "1,2,3,4,5,".split(',')
		gongzuotaiduLists.value = "1,2,3,4,5,".split(',')
		yewunengliLists.value = "1,2,3,4,5,".split(',')
		gongzuojixiaoLists.value = "1,2,3,4,5,".split(',')
		pingjiadengjiLists.value = "дјҳз§Җ,иүҜеҘҪ,дёҖиҲ¬,е·®".split(',')
	}
	//еҲқе§ӢеҢ–
	//еҸ–ж¶Ҳ
	const backClick = () => {
		history.back()
	}
	//е‘ҳе·Ҙе·ҘеҸ·еӣһи°ғ
	const yuangonggonghaoChange=()=>{
		context?.$http({
			url: `follow/yuangong/yuangonggonghao?columnValue=` + form.value.yuangonggonghao,
			method: 'get'
		}).then(res=>{
			//еёҰеҮәе‘ҳе·Ҙе§“еҗҚеӯ—ж®ө
			if(res.data.data.yuangongxingming){
				form.value.yuangongxingming = res.data.data.yuangongxingming
			}
			//еёҰеҮәйғЁй—Ёеӯ—ж®ө
			if(res.data.data.bumen){
				form.value.bumen = res.data.data.bumen
			}
		})
	}
	//жҸҗдәӨ
	const save=()=>{
		var table = crossTable.value
		var objcross = JSON.parse(JSON.stringify(crossRow.value))
		let crossUserId = ''
		let crossRefId = ''
		let crossOptNum = ''
		if(type.value == 'cross'){
			if(crossColumnName.value!=''){
				if(!crossColumnName.value.startsWith('[')){
					for(let o in objcross){
						if(o == crossColumnName.value){
							objcross[o] = crossColumnValue.value
						}
					}
					//дҝ®ж”№и·ЁиЎЁж•°жҚ®
					changeCrossData(objcross)
				}else{
					crossUserId = context?.$toolUtil.storageGet('userid')
					crossRefId = objcross['id']
					crossOptNum = crossColumnName.value.replace(/\[/,"").replace(/\]/,"")
				}
			}
		}
		formRef.value.validate((valid)=>{
			if(valid){
				if(crossUserId&&crossRefId){
					form.value.crossuserid = crossUserId
					form.value.crossrefid = crossRefId
					let params = {
						page: 1,
						limit: 1000, 
						crossuserid:form.value.crossuserid,
						crossrefid:form.value.crossrefid,
					}
					context?.$http({
						url: `${tableName}/page`,
						method: 'get', 
						params: params 
					}).then(res=>{
						if(res.data.data.total>=crossOptNum){
							context?.$toolUtil.message(`${crossTips.value}`,'error')
							return false
						}else{
							context?.$http({
								url: `${tableName}/${!form.value.id ? "save" : "update"}`,
								method: 'post', 
								data: form.value 
							}).then(res=>{
								context?.$toolUtil.message(`ж“ҚдҪңжҲҗеҠҹ`,'success',()=>{
									history.back()
								})
							})
						}
					})
				}else{
					context?.$http({
						url: `${tableName}/${!form.value.id ? "save" : "update"}`,
						method: 'post', 
						data: form.value 
					}).then(res=>{
						context?.$toolUtil.message(`ж“ҚдҪңжҲҗеҠҹ`,'success',()=>{
							history.back()
						})
					})
				}
			}
		})
	}
	//дҝ®ж”№и·ЁиЎЁж•°жҚ®
	const changeCrossData=(row)=>{
		context?.$http({
			url: `${crossTable.value}/update`,
			method: 'post',
			data: row
		}).then(res=>{})
	}
	onMounted(()=>{
		type.value = route.query.type?route.query.type:'add'
		let row = null
		let table = null
		let statusColumnName = null
		let tips = null
		let statusColumnValue = null
		if(type.value == 'cross'){
			row = context?.$toolUtil.storageGet('crossObj')?JSON.parse(context?.$toolUtil.storageGet('crossObj')):{}
			table = context?.$toolUtil.storageGet('crossTable')
			statusColumnName = context?.$toolUtil.storageGet('crossStatusColumnName')
			tips = context?.$toolUtil.storageGet('crossTips')
			statusColumnValue = context?.$toolUtil.storageGet('crossStatusColumnValue')
		}
		init(route.query.id?route.query.id:null, type.value,'', row, table, statusColumnName, tips, statusColumnValue)
	})
	
</script>
<style lang="scss" scoped>
	// йқўеҢ…еұ‘зӣ’еӯҗ
