	// еӨҡзә§иҒ”еҠЁеҸӮж•°
	//жіЁеҶҢжҢүй’®
	const handleRegister = () => {
		let url = tableName.value +"/register";
		if((!registerForm.value.yonghuzhanghao)){
			context?.$toolUtil.message(`з”ЁжҲ·иҙҰеҸ·дёҚиғҪдёәз©ә`,'error')
			return false
