		if((!registerForm.value.yonghumima)){
			context?.$toolUtil.message(`з”ЁжҲ·еҜҶз ҒдёҚиғҪдёәз©ә`,'error')
			return false
		}
		if((!registerForm.value.yonghuxingming)){
			context?.$toolUtil.message(`з”ЁжҲ·е§“еҗҚдёҚиғҪдёәз©ә`,'error')
			return false
		}
		if(registerForm.value.touxiang!=null){
			registerForm.value.touxiang = registerForm.value.touxiang.replace(new RegExp(context?.$config.url,"g"),"");
		}
		if(registerForm.value.shoujihaoma&&(!context?.$toolUtil.isMobile(registerForm.value.shoujihaoma))){
			context?.$toolUtil.message(`жүӢжңәеҸ·з Ғеә”иҫ“е…ҘжүӢжңәж јејҸ`,'error')
			return false
		}
		
		context?.$http({
			url:url,
			method:'post',
			data:registerForm.value
		}).then(res=>{
			context?.$toolUtil.message('жіЁеҶҢжҲҗеҠҹ','success', obj=>{
				context?.$router.push({
					path: "/login"
				});
			})
		})
	}
	//е…¬е…ұж–№жі•
