							:disabled="!isAdd||disabledForm.fengmian?true:false"
							action="file/upload" 
							tip="иҜ·дёҠдј е°Ғйқў" 
							:limit="3" 
							style="width: 100%;text-align: left;"
							:fileUrls="form.fengmian?form.fengmian:''" 
							@change="fengmianUploadSuccess">
						</uploads>
					</el-form-item>
				</el-col>
				<el-col :span="8">
					<el-form-item label="еә•и–Ә" prop="dixin">
						<el-input class="list_inp" v-model.number="form.dixin" placeholder="еә•и–Ә"
							 type="number" 							:readonly="!isAdd||disabledForm.dixin?true:false" />
					</el-form-item>
				</el-col>

				<el-col :span="8">
					<el-form-item label="з»©ж•Ҳ" prop="jixiao">
						<el-input class="list_inp" v-model.number="form.jixiao" placeholder="з»©ж•Ҳ"
							 type="number" 							:readonly="!isAdd||disabledForm.jixiao?true:false" />
					</el-form-item>
				</el-col>

				<el-col :span="8">
					<el-form-item label="еҘ–йҮ‘" prop="jiangjin">
						<el-input class="list_inp" v-model.number="form.jiangjin" placeholder="еҘ–йҮ‘"
							 type="number" 							:readonly="!isAdd||disabledForm.jiangjin?true:false" />
					</el-form-item>
				</el-col>

				<el-col :span="8">
					<el-form-item label="е…ЁеӢӨеҘ–" prop="quanqinjiang">
						<el-input class="list_inp" v-model.number="form.quanqinjiang" placeholder="е…ЁеӢӨеҘ–"
							 type="number" 							:readonly="!isAdd||disabledForm.quanqinjiang?true:false" />
					</el-form-item>
				</el-col>

				<el-col :span="8">
					<el-form-item label="дә”йҷ©дёҖйҮ‘" prop="wuxianyijin">
						<el-input class="list_inp" v-model.number="form.wuxianyijin" placeholder="дә”йҷ©дёҖйҮ‘"
							 type="number" 							:readonly="!isAdd||disabledForm.wuxianyijin?true:false" />
					</el-form-item>
				</el-col>

				<el-col :span="8">
					<el-form-item label="жүЈж¬ҫ" prop="koukuan">
						<el-input class="list_inp" v-model.number="form.koukuan" placeholder="жүЈж¬ҫ"
							 type="number" 							:readonly="!isAdd||disabledForm.koukuan?true:false" />
					</el-form-item>
				</el-col>

				<el-col :span="24">
					<el-form-item label="еӨҮжіЁ" prop="beizhu">
						<el-input v-model="form.beizhu" placeholder="еӨҮжіЁ" type="textarea"
						:readonly="!isAdd||disabledForm.beizhu?true:false"
						/>
					</el-form-item>
				</el-col>
			</el-row>
			<div class="formModel_btn_box">
				<el-button class="formModel_cancel" @click="backClick">еҸ–ж¶Ҳ</el-button>
				<el-button class="formModel_confirm" @click="save"
					type="success"
					>
					дҝқеӯҳ
				</el-button>
			</div>
		</el-form>
	</div>
</template>
<script setup>
	import {
		ref,
		getCurrentInstance,
		watch,
		onUnmounted,
		onMounted,
		nextTick,
		computed
	} from 'vue';
	import {
		useRoute,
		useRouter
	} from 'vue-router';
	const context = getCurrentInstance()?.appContext.config.globalProperties;
	const route = useRoute()
	const router = useRouter()
	//еҹәзЎҖдҝЎжҒҜ
	const tableName = 'xinchoubiaozhun'
	const formName = 'и–Әй…¬ж ҮеҮҶ'
	//еҹәзЎҖдҝЎжҒҜ
	const breadList = ref([{
		name: formName
	}])
	//иҺ·еҸ–е”ҜдёҖж ҮиҜҶ
	const getUUID =()=> {
      return new Date().getTime();
    }
	//formиЎЁеҚ•
	const form = ref({
		biaoti: '',
		fengmian: '',
		dixin: '',
		jixiao: '',
		jiangjin: '',
		quanqinjiang: '',
		wuxianyijin: '',
		koukuan: '',
		beizhu: '',
	})
	const formRef = ref(null)
	const id = ref(0)
	const type = ref('')
	const disabledForm = ref({
		biaoti : false,
		fengmian : false,
		dixin : false,
		jixiao : false,
		jiangjin : false,
		quanqinjiang : false,
		wuxianyijin : false,
		koukuan : false,
		beizhu : false,
	})
	const isAdd = ref(false)
	//иЎЁеҚ•йӘҢиҜҒ
	//еҢ№й…Қж•ҙж•°
	const validateIntNumber = (rule, value, callback) => {
		if (!value) {
			callback();
		} else if (!context?.$toolUtil.isIntNumer(value)) {
			callback(new Error("иҜ·иҫ“е…Ҙж•ҙж•°"));
		} else {
			callback();
		}
	}
	//еҢ№й…Қж•°еӯ—
	const validateNumber = (rule, value, callback) => {
		if(!value){
			callback();
		} else if (!context?.$toolUtil.isNumber(value)) {
			callback(new Error("иҜ·иҫ“е…Ҙж•°еӯ—"));
		} else {
			callback();
		}
	}
	//еҢ№й…ҚжүӢжңәеҸ·з Ғ
	const validateMobile = (rule, value, callback) => {
		if(!value){
			callback();
		} else if (!context?.$toolUtil.isMobile(value)) {
			callback(new Error("иҜ·иҫ“е…ҘжӯЈзЎ®зҡ„жүӢжңәеҸ·з Ғ"));
		} else {
			callback();
		}
	}
	//еҢ№й…Қз”өиҜқеҸ·з Ғ
	const validatePhone = (rule, value, callback) => {
		if(!value){
			callback();
		} else if (!context?.$toolUtil.isPhone(value)) {
			callback(new Error("иҜ·иҫ“е…ҘжӯЈзЎ®зҡ„з”өиҜқеҸ·з Ғ"));
		} else {
			callback();
		}
	}
	//еҢ№й…ҚйӮ®з®ұ
	const validateEmail = (rule, value, callback) => {
		if(!value){
			callback();
		} else if (!context?.$toolUtil.isEmail(value)) {
			callback(new Error("иҜ·иҫ“е…ҘжӯЈзЎ®зҡ„йӮ®з®ұең°еқҖ"));
		} else {
			callback();
		}
	}
	//еҢ№й…Қиә«д»ҪиҜҒ
	const validateIdCard = (rule, value, callback) => {
		if(!value){
			callback();
		} else if (!context?.$toolUtil.checkIdCard(value)) {
			callback(new Error("иҜ·иҫ“е…ҘжӯЈзЎ®зҡ„иә«д»ҪиҜҒеҸ·з Ғ"));
		} else {
			callback();
		}
	}
	//еҢ№й…ҚзҪ‘з«ҷең°еқҖ
	const validateUrl = (rule, value, callback) => {
		if(!value){
			callback();
		} else if (!context?.$toolUtil.isURL(value)) {
			callback(new Error("иҜ·иҫ“е…ҘжӯЈзЎ®зҡ„URLең°еқҖ"));
		} else {
			callback();
		}
	}
	const rules = ref({
		biaoti: [
		],
		fengmian: [
		],
		dixin: [
			{required: true,message: 'иҜ·иҫ“е…Ҙ',trigger: 'blur'}, 
			{ validator: validateNumber, trigger: 'blur' },
		],
		jixiao: [
			{required: true,message: 'иҜ·иҫ“е…Ҙ',trigger: 'blur'}, 
			{ validator: validateNumber, trigger: 'blur' },
		],
		jiangjin: [
			{required: true,message: 'иҜ·иҫ“е…Ҙ',trigger: 'blur'}, 
			{ validator: validateNumber, trigger: 'blur' },
		],
		quanqinjiang: [
			{required: true,message: 'иҜ·иҫ“е…Ҙ',trigger: 'blur'}, 
			{ validator: validateNumber, trigger: 'blur' },
		],
		wuxianyijin: [
			{required: true,message: 'иҜ·иҫ“е…Ҙ',trigger: 'blur'}, 
			{ validator: validateNumber, trigger: 'blur' },
		],
		koukuan: [
			{required: true,message: 'иҜ·иҫ“е…Ҙ',trigger: 'blur'}, 
			{ validator: validateNumber, trigger: 'blur' },
		],
		beizhu: [
		],
	})
	//е°ҒйқўдёҠдј еӣһи°ғ
	const fengmianUploadSuccess=(e)=>{
		form.value.fengmian = e
	}
	//methods

	//methods
	//иҺ·еҸ–info
	const getInfo = ()=>{
		context?.$http({
			url: `${tableName}/info/${id.value}`,
			method: 'get'
		}).then(res => {
			let reg=new RegExp('../../../file','g')
			form.value = res.data.data
		})
	}
	const crossRow = ref('')
	const crossTable = ref('')
	const crossTips = ref('')
	const crossColumnName = ref('')
	const crossColumnValue = ref('')
	//еҲқе§ӢеҢ–
	const init = (formId=null,formType='add',formNames='',row=null,table=null,statusColumnName=null,tips=null,statusColumnValue=null) => {
		if(formId){
			id.value = formId
			type.value = formType
		}
		if(formType == 'add'){
			isAdd.value = true
		}else if(formType == 'info'){
			isAdd.value = false
			getInfo()
		}else if(formType == 'edit'){
			isAdd.value = true
			getInfo()
		}
		else if(formType == 'cross'){
			isAdd.value = true
			// getInfo()
			for(let x in row){
				if(x=='biaoti'){
					form.value.biaoti = row[x];
					disabledForm.value.biaoti = true;
					continue;
				}
				if(x=='fengmian'){
					form.value.fengmian = row[x];
					disabledForm.value.fengmian = true;
					continue;
				}
				if(x=='dixin'){
					form.value.dixin = row[x];
					disabledForm.value.dixin = true;
					continue;
				}
				if(x=='jixiao'){
					form.value.jixiao = row[x];
					disabledForm.value.jixiao = true;
					continue;
				}
				if(x=='jiangjin'){
					form.value.jiangjin = row[x];
					disabledForm.value.jiangjin = true;
					continue;
				}
				if(x=='quanqinjiang'){
					form.value.quanqinjiang = row[x];
					disabledForm.value.quanqinjiang = true;
					continue;
				}
				if(x=='wuxianyijin'){
					form.value.wuxianyijin = row[x];
					disabledForm.value.wuxianyijin = true;
					continue;
				}
				if(x=='koukuan'){
					form.value.koukuan = row[x];
					disabledForm.value.koukuan = true;
					continue;
				}
				if(x=='beizhu'){
					form.value.beizhu = row[x];
					disabledForm.value.beizhu = true;
					continue;
				}
			}
			if(row){
				crossRow.value = row
			}
			if(table){
				crossTable.value = table
			}
			if(tips){
				crossTips.value = tips
			}
			if(statusColumnName){
				crossColumnName.value = statusColumnName
			}
			if(statusColumnValue){
				crossColumnValue.value = statusColumnValue
			}
		}
		context?.$http({
			url: `${context?.$toolUtil.storageGet('frontSessionTable')}/session`,
			method: 'get'
		}).then(res => {
			var json = res.data.data
		})
	}
	//еҲқе§ӢеҢ–
	//еҸ–ж¶Ҳ
	const backClick = () => {
		history.back()
	}
	//жҸҗдәӨ
	const save=()=>{
		if(form.value.fengmian!=null) {
			form.value.fengmian = form.value.fengmian.replace(new RegExp(context?.$config.url,"g"),"");
		}
		var table = crossTable.value
		var objcross = JSON.parse(JSON.stringify(crossRow.value))
		let crossUserId = ''
		let crossRefId = ''
		let crossOptNum = ''
		if(type.value == 'cross'){
			if(crossColumnName.value!=''){
				if(!crossColumnName.value.startsWith('[')){
					for(let o in objcross){
						if(o == crossColumnName.value){
							objcross[o] = crossColumnValue.value
						}
					}
					//дҝ®ж”№и·ЁиЎЁж•°жҚ®
					changeCrossData(objcross)
				}else{
					crossUserId = context?.$toolUtil.storageGet('userid')
					crossRefId = objcross['id']
					crossOptNum = crossColumnName.value.replace(/\[/,"").replace(/\]/,"")
				}
			}
		}
		formRef.value.validate((valid)=>{
			if(valid){
				if(crossUserId&&crossRefId){
					form.value.crossuserid = crossUserId
					form.value.crossrefid = crossRefId
					let params = {
						page: 1,
						limit: 1000, 
						crossuserid:form.value.crossuserid,
						crossrefid:form.value.crossrefid,
					}
					context?.$http({
						url: `${tableName}/page`,
						method: 'get', 
						params: params 
					}).then(res=>{
						if(res.data.data.total>=crossOptNum){
							context?.$toolUtil.message(`${crossTips.value}`,'error')
							return false
						}else{
							context?.$http({
								url: `${tableName}/${!form.value.id ? "save" : "update"}`,
								method: 'post', 
								data: form.value 
							}).then(res=>{
								context?.$toolUtil.message(`ж“ҚдҪңжҲҗеҠҹ`,'success',()=>{
									history.back()
								})
							})
						}
					})
				}else{
					context?.$http({
						url: `${tableName}/${!form.value.id ? "save" : "update"}`,
						method: 'post', 
						data: form.value 
					}).then(res=>{
						context?.$toolUtil.message(`ж“ҚдҪңжҲҗеҠҹ`,'success',()=>{
							history.back()
						})
					})
				}
			}
		})
	}
	//дҝ®ж”№и·ЁиЎЁж•°жҚ®
	const changeCrossData=(row)=>{
		context?.$http({
			url: `${crossTable.value}/update`,
			method: 'post',
			data: row
		}).then(res=>{})
	}
	onMounted(()=>{
		type.value = route.query.type?route.query.type:'add'
		let row = null
		let table = null
		let statusColumnName = null
		let tips = null
		let statusColumnValue = null
		if(type.value == 'cross'){
			row = context?.$toolUtil.storageGet('crossObj')?JSON.parse(context?.$toolUtil.storageGet('crossObj')):{}
			table = context?.$toolUtil.storageGet('crossTable')
			statusColumnName = context?.$toolUtil.storageGet('crossStatusColumnName')
			tips = context?.$toolUtil.storageGet('crossTips')
			statusColumnValue = context?.$toolUtil.storageGet('crossStatusColumnValue')
		}
		init(route.query.id?route.query.id:null, type.value,'', row, table, statusColumnName, tips, statusColumnValue)
	})
	
</script>
<style lang="scss" scoped>
